"use client";

import { Users, UserPlus, Search, Filter, MoreHorizontal, Mail, Phone, MapPin } from "lucide-react";
import { motion } from "framer-motion";
import { useState } from "react";

export default function MembersPage() {
    const [searchTerm, setSearchTerm] = useState("");
    const [filter, setFilter] = useState("Todos");

    const members = [
        { id: 1, name: "Maria García", role: "Fallera Mayor", status: "Activo", email: "maria.garcia@example.com", avatar: "MG", color: "bg-rose-100 text-rose-600" },
        { id: 2, name: "Jose Martínez", role: "Presidente", status: "Activo", email: "jose.martinez@example.com", avatar: "JM", color: "bg-blue-100 text-blue-600" },
        { id: 3, name: "Lucía Sanchis", role: "Fallero", status: "Pendiente", email: "lucia.sanchis@example.com", avatar: "LS", color: "bg-amber-100 text-amber-600" },
        { id: 4, name: "Antonio Ruiz", role: "Fallero de Honor", status: "Activo", email: "antonio.ruiz@example.com", avatar: "AR", color: "bg-emerald-100 text-emerald-600" },
        { id: 5, name: "Carla Esteve", role: "Infantil", status: "Inactivo", email: "carla.esteve@example.com", avatar: "CE", color: "bg-purple-100 text-purple-600" },
        { id: 6, name: "Pedro Almodóvar", role: "Vocal", status: "Activo", email: "pedro.almodovar@example.com", avatar: "PA", color: "bg-slate-100 text-slate-600" },
    ];

    const filteredMembers = members.filter(member =>
        member.name.toLowerCase().includes(searchTerm.toLowerCase()) &&
        (filter === "Todos" || member.status === filter)
    );

    return (
        <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4 }}
            className="space-y-8"
        >
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-foreground">Censo Fallero</h2>
                    <p className="text-muted-foreground mt-1">Gestión de falleros, cargos y estados.</p>
                </div>
                <button className="inline-flex items-center justify-center rounded-xl text-sm font-medium transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring bg-primary text-primary-foreground hover:bg-primary/90 hover:shadow-lg h-10 px-5 shadow-sm">
                    <UserPlus className="mr-2 h-4 w-4" />
                    Añadir Fallero
                </button>
            </div>

            <div className="flex flex-col sm:flex-row gap-4 items-center bg-card p-4 rounded-2xl shadow-sm border border-border/50">
                <div className="relative w-full sm:w-[320px]">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <input
                        type="text"
                        placeholder="Buscar por nombre..."
                        className="w-full h-10 pl-9 pr-4 rounded-lg border border-input bg-background/50 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
                <div className="flex gap-2 w-full sm:w-auto overflow-x-auto pb-1 sm:pb-0">
                    {["Todos", "Activo", "Pendiente", "Inactivo"].map((status) => (
                        <button
                            key={status}
                            onClick={() => setFilter(status)}
                            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${filter === status
                                    ? "bg-slate-900 text-white dark:bg-slate-50 dark:text-slate-900 shadow-md"
                                    : "bg-muted text-muted-foreground hover:bg-slate-200 dark:hover:bg-slate-800"
                                }`}
                        >
                            {status}
                        </button>
                    ))}
                </div>
                <button className="ml-auto p-2 text-muted-foreground hover:text-foreground rounded-lg hover:bg-muted transition-colors">
                    <Filter className="h-5 w-5" />
                </button>
            </div>

            <div className="rounded-2xl border bg-card text-card-foreground shadow-sm overflow-hidden">
                <div className="relative w-full overflow-auto">
                    <table className="w-full caption-bottom text-sm text-left">
                        <thead className="[&_tr]:border-b bg-muted/30">
                            <tr className="border-b transition-colors data-[state=selected]:bg-muted">
                                <th className="h-12 px-6 align-middle font-medium text-muted-foreground">Fallero</th>
                                <th className="h-12 px-6 align-middle font-medium text-muted-foreground">Cargo</th>
                                <th className="h-12 px-6 align-middle font-medium text-muted-foreground">Contacto</th>
                                <th className="h-12 px-6 align-middle font-medium text-muted-foreground">Estado</th>
                                <th className="h-12 px-6 text-right align-middle font-medium text-muted-foreground">Acciones</th>
                            </tr>
                        </thead>
                        <tbody className="[&_tr:last-child]:border-0">
                            {filteredMembers.map((member, index) => (
                                <motion.tr
                                    key={member.id}
                                    initial={{ opacity: 0, x: -10 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: index * 0.05 }}
                                    className="border-b transition-colors hover:bg-slate-50/80 dark:hover:bg-slate-800/30 group"
                                >
                                    <td className="p-6 align-middle">
                                        <div className="flex items-center gap-4">
                                            <div className={`h-10 w-10 rounded-full flex items-center justify-center font-bold text-sm ${member.color}`}>
                                                {member.avatar}
                                            </div>
                                            <div>
                                                <div className="font-semibold text-foreground">{member.name}</div>
                                                <div className="text-xs text-muted-foreground">ID: #{member.id.toString().padStart(4, '0')}</div>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="p-6 align-middle">
                                        <span className="inline-flex items-center rounded-md bg-slate-100 px-2 py-1 text-xs font-medium text-slate-600 ring-1 ring-inset ring-slate-500/10 dark:bg-slate-400/10 dark:text-slate-400">
                                            {member.role}
                                        </span>
                                    </td>
                                    <td className="p-6 align-middle">
                                        <div className="flex flex-col gap-1">
                                            <div className="flex items-center text-xs text-muted-foreground">
                                                <Mail className="mr-1.5 h-3 w-3" />
                                                {member.email}
                                            </div>
                                            <div className="flex items-center text-xs text-muted-foreground">
                                                <Phone className="mr-1.5 h-3 w-3" />
                                                +34 600 000 000
                                            </div>
                                        </div>
                                    </td>
                                    <td className="p-6 align-middle">
                                        <span className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-semibold ring-1 ring-inset ${member.status === "Activo" ? "bg-green-50 text-green-700 ring-green-600/20 dark:bg-green-900/10 dark:text-green-400" :
                                                member.status === "Pendiente" ? "bg-yellow-50 text-yellow-800 ring-yellow-600/20 dark:bg-yellow-900/10 dark:text-yellow-500" :
                                                    "bg-gray-50 text-gray-600 ring-gray-500/10 dark:bg-gray-900/10 dark:text-gray-400"
                                            }`}>
                                            <span className={`mr-1.5 h-1.5 w-1.5 rounded-full ${member.status === "Activo" ? "bg-green-600" :
                                                    member.status === "Pendiente" ? "bg-yellow-600" : "bg-gray-500"
                                                }`}></span>
                                            {member.status}
                                        </span>
                                    </td>
                                    <td className="p-6 align-middle text-right">
                                        <button className="text-muted-foreground hover:text-foreground p-2 rounded-full hover:bg-muted transition-colors opacity-0 group-hover:opacity-100 focus:opacity-100">
                                            <MoreHorizontal className="h-4 w-4" />
                                        </button>
                                    </td>
                                </motion.tr>
                            ))}
                        </tbody>
                    </table>
                </div>
                {filteredMembers.length === 0 && (
                    <div className="p-12 text-center text-muted-foreground">
                        <Search className="h-12 w-12 mx-auto mb-4 opacity-20" />
                        No se encontraron falleros con ese filtro.
                    </div>
                )}
            </div>
        </motion.div>
    );
}
